<?php include __DIR__ . '/../../includes/header.php'; require_permission('areas.ver');
if($_SERVER['REQUEST_METHOD']==='POST'){ if(!empty($_POST['id_area'])){$pdo->prepare("UPDATE areas_restringidas SET nombre_area=?, nivel_seguridad=?, horario_permitido=? WHERE id_area=?")->execute([$_POST['nombre_area'],$_POST['nivel_seguridad'],$_POST['horario_permitido'],$_POST['id_area']]);} else {$pdo->prepare("INSERT INTO areas_restringidas(nombre_area,nivel_seguridad,horario_permitido) VALUES(?,?,?)")->execute([$_POST['nombre_area'],$_POST['nivel_seguridad'],$_POST['horario_permitido']]);} log_event('GUARDAR_AREA','Área restringida'); flash('success','Área guardada.'); redirect('index.php');}
$rows=$pdo->query("SELECT * FROM areas_restringidas ORDER BY id_area")->fetchAll(); $edit=null; if(isset($_GET['edit'])){$st=$pdo->prepare("SELECT * FROM areas_restringidas WHERE id_area=?");$st->execute([$_GET['edit']]);$edit=$st->fetch();}
?>
<h1>Áreas restringidas</h1><div class="two-col"><div class="card"><h2><?= $edit?'Editar':'Nueva' ?> área</h2><form method="POST"><input type="hidden" name="id_area" value="<?= e($edit['id_area']??'') ?>"><label>Nombre</label><input name="nombre_area" value="<?= e($edit['nombre_area']??'') ?>" required><label>Nivel seguridad</label><select name="nivel_seguridad"><option>BAJO</option><option <?= ($edit['nivel_seguridad']??'')=='MEDIO'?'selected':'' ?>>MEDIO</option><option <?= ($edit['nivel_seguridad']??'')=='ALTO'?'selected':'' ?>>ALTO</option></select><label>Horario permitido</label><input name="horario_permitido" value="<?= e($edit['horario_permitido']??'08:00-18:00') ?>"><br><br><button>Guardar</button></form></div><div class="card"><table><tr><th>ID</th><th>Área</th><th>Nivel</th><th>Horario</th><th></th></tr><?php foreach($rows as $r): ?><tr><td><?= $r['id_area'] ?></td><td><?= e($r['nombre_area']) ?></td><td><?= e($r['nivel_seguridad']) ?></td><td><?= e($r['horario_permitido']) ?></td><td><a class="btn btn-secondary" href="?edit=<?= $r['id_area'] ?>">Editar</a></td></tr><?php endforeach; ?></table></div></div><?php include __DIR__ . '/../../includes/footer.php'; ?>
